import React from 'react';
import { Outlet, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const StaffLayout = () => {
  const { logout, user } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#f3f4f6' }}>
      <div style={{ width: '240px', background: 'white', display: 'flex', flexDirection: 'column', padding: '20px', boxShadow: '2px 0 5px rgba(0,0,0,0.05)' }}>
        <div style={{ marginBottom: '30px', textAlign: 'center', color: '#003366', fontWeight: 'bold', fontSize: '1.2rem' }}>
           PORTAL
        </div>
        
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '10px' }}>
          <Link to="/staff/attendance" style={linkStyle}>🕒 Chấm công</Link>
          <Link to="/staff/tasks" style={linkStyle}>📋 Nhiệm vụ</Link>
          <Link to="/staff/facility" style={linkStyle}>🛠️ CSVC</Link>
          <Link to="/staff/reports" style={linkStyle}>📊 Báo cáo</Link> {/* MỚI */}
          <Link to="/staff/performance" style={linkStyle}>⭐ Hiệu suất</Link>
        </div>

        <div style={{ borderTop: '1px solid #eee', paddingTop: '20px' }}>
          <div style={{ fontSize: '0.85rem', color: '#666', marginBottom: '10px' }}>{user?.name}</div>
          <button onClick={handleLogout} style={{ width: '100%', padding: '8px', background: '#f3f4f6', border: '1px solid #ddd', borderRadius: '4px', cursor: 'pointer' }}>
            Đăng xuất
          </button>
        </div>
      </div>

      <div style={{ flex: 1, padding: '20px', overflowY: 'auto' }}>
        <Outlet />
      </div>
    </div>
  );
};

const linkStyle = {
  textDecoration: 'none', color: '#374151', padding: '10px', borderRadius: '6px',
  transition: 'background 0.2s', display: 'block', fontWeight: '500'
};

export default StaffLayout;
